SELECT AVG(mpg) AS average_mpg
FROM vehicles
WHERE mpg = (SELECT MAX(mpg) FROM vehicles);

SELECT manufacturer_name
FROM manufacturers
ORDER BY established_year ASC;

SELECT AVG(mpg) AS average_mpg
FROM vehicles
WHERE manufacturer_id = (SELECT manufacturer_id FROM manufacturers WHERE manufacturer_name = 'Honda');

SELECT AVG(mpg) AS average_mpg
FROM vehicles
WHERE origin = 1 AND horsepower BETWEEN 100 AND 200;
